export function getNeighborhoodPage(slug: NeighborhoodSlug): NeighborhoodPageContent {
  const entry = neighborhoods.find((item) => item.slug === slug);
  if (!entry) throw new Error(`Neighborhood page missing for slug: ${slug}`);
  return entry;
}
